import "core-js/modules/es.array.push.js";
import "core-js/modules/esnext.iterator.constructor.js";
import "core-js/modules/esnext.iterator.filter.js";
import Request from '@/utils/request';
import Pagination from '@/components/Pagination/index.vue';
import CountTo from 'vue-count-to';
import excel from '@/utils/excel.js';
import { hasInviteCode, isValidDate } from '@/utils/inviteCode';
export default {
  name: 'UserManager',
  components: {
    Pagination,
    CountTo
  },
  inject: ['userInfo'],
  data() {
    // 邮箱验证规则
    const validateEmail = (rule, value, callback) => {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      if (!value) {
        callback(new Error('请输入邮箱地址'));
      } else if (!emailRegex.test(value)) {
        callback(new Error('请输入正确的邮箱地址'));
      } else {
        callback();
      }
    };
    return {
      // 搜索表单
      searchForm: {
        username: '',
        role: '',
        status: ''
      },
      // 查询参数
      queryParams: {
        currentPage: 1,
        size: 10
      },
      // 用户列表
      users: [],
      // 总数
      total: 0,
      // 加载状态
      listLoading: false,
      // 对话框显示
      dialogVisible: false,
      // 对话框标题
      dialogTitle: '',
      // 对话框模式
      dialogMode: 'add',
      // 导出数据弹出框显示/隐藏
      exportVisible: false,
      // 导出进度
      exportProgress: 0,
      // 是否正在导出
      isExporting: false,
      // 导出进度文本
      exportProgressText: '',
      // 表单数据
      form: {
        username: '',
        name: '',
        email: '',
        password: '',
        role: '',
        status: 1
      },
      // 用户统计
      userStats: {
        normalUsers: 0,
        userTotal: 0,
        admins: 0,
        disabled: 0
      },
      // 表单校验规则
      rules: {
        username: [{
          required: true,
          message: '请输入用户名',
          trigger: 'blur'
        }, {
          min: 3,
          max: 20,
          message: '长度在 3 到 20 个字符',
          trigger: 'blur'
        }],
        name: [{
          required: true,
          message: '请输入真实姓名',
          trigger: 'blur'
        }],
        email: [{
          required: true,
          validator: validateEmail,
          trigger: 'blur'
        }],
        password: [{
          required: true,
          message: '请输入密码',
          trigger: 'blur'
        }, {
          min: 6,
          message: '密码长度不能小于6位',
          trigger: 'blur'
        }],
        role: [{
          required: true,
          message: '请选择用户角色',
          trigger: 'change'
        }]
      },
      // 添加当前用户角色相关数据
      currentRole: '',
      roleOptions: [] // 动态角色选项
    };
  },
  created() {
    this.checkInviteCode();
    this.currentRole = this.userInfo.role;
    this.initRoleOptions();
    this.getList();
  },
  methods: {
    checkInviteCode() {
      if (!isValidDate()) {
        this.$message.error('邀请日期已过期，无法使用系统');
        setTimeout(() => {
          this.$router.push('/login');
        }, 2000);
        return;
      }
      if (!hasInviteCode()) {
        this.$message.warning('请先验证邀请码');
        setTimeout(() => {
          this.$router.push('/login');
        }, 2000);
        return;
      }
    },
    // 初始化角色选项
    initRoleOptions() {
      switch (this.currentRole) {
        case 'USER':
          this.roleOptions = [{
            label: '普通用户',
            value: 'USER'
          }];
          break;
        case 'ADMIN':
          this.roleOptions = [{
            label: '管理员',
            value: 'ADMIN'
          }, {
            label: '普通用户',
            value: 'USER'
          }];
          break;
        default:
          this.roleOptions = [{
            label: '普通用户',
            value: 'USER'
          }, {
            label: '管理员',
            value: 'ADMIN'
          }];
      }
    },
    // 获取用户列表
    async getList() {
      this.listLoading = true;
      try {
        const params = {
          ...this.queryParams,
          ...this.searchForm
        };
        const res = await Request.get('/user/page', {
          params
        });
        if (res.code === '0') {
          // 修改用户列表过滤逻辑
          this.users = res.data.records.filter(user => {
            // 管理员可以看到普通用户和管理员
            if (this.currentRole === 'ADMIN') {
              return ['USER', 'ADMIN'].includes(user.role);
            }
            // 普通用户只能看到自己
            if (this.currentRole === 'USER') {
              return user.id === this.userInfo.id;
            }
            return false;
          });
          // 使用后端返回的总数，而不是过滤后的长度
          this.total = res.data.total;
          this.calculateUserStats();
        }
      } catch (error) {
        // 静默处理获取用户列表失败
      } finally {
        this.listLoading = false;
      }
    },
    // 计算用户统计数据
    calculateUserStats() {
      this.userStats = {
        normalUsers: this.users.filter(user => user.role === 'USER').length,
        userTotal: this.users.length,
        admins: this.users.filter(user => user.role === 'ADMIN').length,
        disabled: this.users.filter(user => user.status === 0).length
      };
    },
    // 搜索
    handleSearch() {
      this.queryParams.currentPage = 1;
      this.getList();
    },
    // 重置搜索
    resetSearch() {
      this.searchForm = {
        username: '',
        role: '',
        status: ''
      };
      this.handleSearch();
    },
    // 新增用户
    handleAdd() {
      this.dialogMode = 'add';
      this.dialogTitle = '新增用户';
      this.form = {
        username: '',
        name: '',
        email: '',
        password: '',
        role: '',
        status: 1
      };
      this.dialogVisible = true;
    },
    // 编辑用户
    handleEdit(row) {
      // 检查权限
      // if (this.currentRole === 'ADMIN' && (row.role === 'SUPER_ADMIN' || row.role === 'ADMIN')) {
      //   this.$message.error('没有权限编辑该用户')
      //   return
      // }

      this.dialogMode = 'edit';
      this.dialogTitle = '编辑用户';
      this.form = {
        ...row
      };
      delete this.form.password;
      this.dialogVisible = true;
    },
    // 删除用户
    handleDelete(row) {
      // 检查权限
      // if (this.currentRole === 'ADMIN' && (row.role === 'SUPER_ADMIN' || row.role === 'ADMIN')) {
      //   this.$message.error('没有权限删除该用户')
      //   return
      // }

      this.$confirm('确认删除该用户?', '提示', {
        type: 'warning'
      }).then(async () => {
        try {
          const res = await Request.delete(`/user/delete/${row.id}`);
          if (res.code === '0') {
            this.$message.success('删除成功');
            this.getList();
          }
        } catch (error) {
          // 静默处理删除用户失败
        }
      }).catch(() => {});
    },
    // 更改用户状态
    async handleStatusChange(row) {
      // 检查权限
      // if (this.currentRole === 'ADMIN' && (row.role === 'SUPER_ADMIN' || row.role === 'ADMIN')) {
      //   this.$message.error('没有权限修改该用户状态')
      //   row.status = row.status === 1 ? 0 : 1 // 恢复状态
      //   return
      // }

      try {
        const res = await Request.put(`/user/${row.id}`, {
          status: row.status
        });
        if (res.code === '0') {
          this.$message.success('状态更新成功');
          this.calculateUserStats();
        } else {
          row.status = row.status === 1 ? 0 : 1;
          this.$message.error('状态更新失败');
        }
      } catch (error) {
        row.status = row.status === 1 ? 0 : 1;
        // 静默处理更新用户状态失败
        this.$message.error('更新失败');
      }
    },
    // 提交表单
    submitForm() {
      this.$refs.form.validate(async valid => {
        if (valid) {
          try {
            const method = this.dialogMode === 'add' ? 'post' : 'put';
            const url = this.dialogMode === 'add' ? '/user/add' : `/user/${this.form.id}`;

            // 添加加载状态
            this.$loading({
              lock: true,
              text: '提交中...',
              spinner: 'el-icon-loading'
            });
            const res = await Request[method](url, this.form);
            if (res.code === '0') {
              this.$message.success(`${this.dialogMode === 'add' ? '添加' : '更新'}成功`);
              this.dialogVisible = false;
              this.getList();
            } else {
              // 处理后端返回的错误
              this.$message.error(res.msg || '操作失败');
            }
          } catch (error) {
            // 静默处理提交表单失败
            this.$message.error(error.response?.data?.msg || '操作失败，请稍后重试');
          } finally {
            // 关闭加载状态
            this.$loading().close();
          }
        } else {
          // 表单验证失败
          this.$message.warning('请填写完整所有必填项');
          return false;
        }
      });
    },
    // 导出数据--excel格式
    async exportTable(type) {
      if (this.users.length) {
        try {
          // 初始化导出状态
          this.isExporting = true;
          this.exportProgress = 0;
          this.exportProgressText = '准备导出...';

          // 进度更新回调函数
          const updateProgress = (progress, text) => {
            this.exportProgress = progress;
            this.exportProgressText = text;
          };

          // 格式化数据（占0-70%）
          updateProgress(10, '正在格式化数据...');
          const exportData = [];
          const totalItems = this.users.length;
          for (let i = 0; i < this.users.length; i++) {
            const user = this.users[i];
            exportData.push({
              ...user,
              role: user.role === 'ADMIN' ? '管理员' : '普通用户',
              status: user.status === 1 ? '启用' : '禁用',
              createdAt: user.createdAt ? new Date(user.createdAt).toLocaleString() : ''
            });

            // 每处理10条更新一次进度
            if ((i + 1) % 10 === 0 || i === this.users.length - 1) {
              const progress = 10 + Math.round((i + 1) / totalItems * 60);
              updateProgress(progress, `正在格式化数据: ${i + 1}/${totalItems}`);
              // 使用 setTimeout 让 UI 有机会更新
              await new Promise(resolve => setTimeout(resolve, 0));
            }
          }

          // 导出文件（占70%-100%）
          updateProgress(75, '正在生成文件...');
          const params = {
            header: ['ID', '用户名', '真实姓名', '邮箱', '角色', '状态', '创建时间'],
            key: ['id', 'username', 'name', 'email', 'role', 'status', 'createdAt'],
            data: exportData,
            autoWidth: true,
            fileName: '用户数据表',
            bookType: type
          };

          // 使用 setTimeout 确保进度条更新
          await new Promise(resolve => setTimeout(resolve, 100));
          updateProgress(90, '正在保存文件...');
          excel.exportDataToExcel(params);

          // 完成
          updateProgress(100, '导出完成！');
          await new Promise(resolve => setTimeout(resolve, 500));
          this.isExporting = false;
          this.exportProgress = 0;
          this.exportProgressText = '';
          this.exportVisible = false;
          this.$message.success('导出成功');
        } catch (error) {
          console.error('导出失败:', error);
          this.isExporting = false;
          this.exportProgress = 0;
          this.exportProgressText = '';
          this.$message.error('导出失败，请稍后重试');
        }
      } else {
        this.$message.warning('暂无数据可导出');
      }
    }
  },
  filters: {
    formatDate(timestamp) {
      if (!timestamp) return '';
      const date = new Date(timestamp);
      return date.toLocaleString();
    }
  }
};
